import{_ as t,o,c as s,a2 as i}from"./chunks/framework.DGp-bpT-.js";const g=JSON.parse('{"title":"Slack Integration Setup","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/slack-setup.md","filePath":"en/guide/slack-setup.md","lastUpdated":1775054555000}'),a={name:"en/guide/slack-setup.md"};function n(l,e,r,c,h,p){return o(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="slack-integration-setup" tabindex="-1">Slack Integration Setup <a class="header-anchor" href="#slack-integration-setup" aria-label="Permalink to &quot;Slack Integration Setup&quot;">​</a></h1><p>SREBot integration with Slack allows it to watch channel messages, identify Alertmanager notifications, and perform automated AI analysis.</p><p>The bot operates in <strong>Socket Mode</strong>, which removes the need for public webhooks and lets you run the bot behind NAT or within a private network.</p><hr><h2 id="_1-creating-a-slack-app" tabindex="-1">1. Creating a Slack App <a class="header-anchor" href="#_1-creating-a-slack-app" aria-label="Permalink to &quot;1. Creating a Slack App&quot;">​</a></h2><ol><li>Go to <a href="https://api.slack.com/apps" target="_blank" rel="noreferrer">Slack API: Your Apps</a>.</li><li>Click <strong>Create New App</strong> -&gt; <strong>From scratch</strong>.</li><li>Name your app (e.g., <code>SREBot</code>) and select your Workspace.</li></ol><h2 id="_2-enabling-socket-mode" tabindex="-1">2. Enabling Socket Mode <a class="header-anchor" href="#_2-enabling-socket-mode" aria-label="Permalink to &quot;2. Enabling Socket Mode&quot;">​</a></h2><ol><li>In the sidebar, select <strong>Settings -&gt; Socket Mode</strong>.</li><li>Toggle <strong>Enable Socket Mode</strong>.</li><li>Slack will prompt you to create an <strong>App-Level Token</strong>. <ul><li>Name it (e.g., <code>srebot-socket-token</code>).</li><li>Add the <code>connections:write</code> scope.</li><li><strong>Save this token</strong> – it starts with <code>xapp-...</code>. In the bot config, this is <code>SLACK_APP_TOKEN</code>.</li></ul></li></ol><h2 id="_3-configuring-permissions-scopes" tabindex="-1">3. Configuring Permissions (Scopes) <a class="header-anchor" href="#_3-configuring-permissions-scopes" aria-label="Permalink to &quot;3. Configuring Permissions (Scopes)&quot;">​</a></h2><ol><li><p>Go to <strong>Features -&gt; OAuth &amp; Permissions</strong>.</p></li><li><p>Scroll to <strong>Scopes</strong> -&gt; <strong>Bot Token Scopes</strong>.</p></li><li><p>Add the following permissions:</p><ul><li><code>channels:history</code> — allow the bot to see messages in public channels.</li><li><code>groups:history</code> — allow the bot to see messages in private channels.</li><li><code>chat:write</code> — allow the bot to send messages.</li><li><code>app_mention:read</code> — allow the bot to react to <code>@</code> mentions.</li></ul></li><li><p>Scroll up and click <strong>Install to Workspace</strong>. After confirmation, you&#39;ll receive a <strong>Bot User OAuth Token</strong> (starts with <code>xoxb-...</code>).</p><ul><li>This is <code>SLACK_BOT_TOKEN</code> in the bot config.</li></ul></li></ol><h2 id="_4-subscribing-to-events" tabindex="-1">4. Subscribing to Events <a class="header-anchor" href="#_4-subscribing-to-events" aria-label="Permalink to &quot;4. Subscribing to Events&quot;">​</a></h2><ol><li>Go to <strong>Features -&gt; Event Subscriptions</strong>.</li><li>Toggle <strong>Enable Events</strong>.</li><li>In the <strong>Subscribe to bot events</strong> section, add: <ul><li><code>message.channels</code></li><li><code>message.groups</code> (if you plan to use it in private channels)</li><li><code>app_mention</code></li></ul></li><li>Click <strong>Save Changes</strong>.</li></ol><h2 id="_5-bot-configuration-env" tabindex="-1">5. Bot Configuration (Env) <a class="header-anchor" href="#_5-bot-configuration-env" aria-label="Permalink to &quot;5. Bot Configuration (Env)&quot;">​</a></h2><p>Add the tokens and your target channel ID to your <code>.env</code> file or Helm configuration:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Bot OAuth Token (xoxb-...)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SLACK_BOT_TOKEN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">xoxb-your-bot-token</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># App Level Token (xapp-...)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SLACK_APP_TOKEN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">xapp-your-app-token</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># The channel ID where the bot should listen for alerts</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SLACK_CHANNEL_ID</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">C0123456789</span></span></code></pre></div><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>To find your channel ID, click on the channel name in Slack -&gt; Settings -&gt; look for &quot;Channel ID&quot; at the bottom.</p></div><h2 id="_6-inviting-the-bot-to-the-channel" tabindex="-1">6. Inviting the Bot to the Channel <a class="header-anchor" href="#_6-inviting-the-bot-to-the-channel" aria-label="Permalink to &quot;6. Inviting the Bot to the Channel&quot;">​</a></h2><p>The bot won&#39;t see any messages unless it&#39;s explicitly added to the channel:</p><ol><li>Go to the desired Slack channel.</li><li>Type <code>/invite @your_bot_name</code>.</li></ol><hr><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><ul><li><strong>Automatic Analysis</strong>: When added to a channel with <code>channels:history</code> permissions, the bot automatically intercepts messages matching Alertmanager patterns and begins its AI audit.</li><li><strong>Mentions</strong>: You can force an analysis by tagging the bot (<code>@SREBot</code>) in an alert message.</li><li><strong>Firing Messages</strong>: The bot posts an <code>🔍 Analyzing...</code> placeholder, then edits it to reveal the full RCA report.</li><li><strong>Resolved Messages</strong>: The bot sends a <code>✅ Resolved: ...</code> update <strong>only if it has already analyzed</strong> that specific alert in its current session. If a resolved notification arrives without prior &quot;firing&quot; tracking, it is ignored silently.</li></ul><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>For your security, the bot automatically redacts Bearer tokens, API keys, and passwords from diagnostic tool outputs before sending them to the LLM. Your sensitive credentials never enter the analysis history.</p></div>`,23)])])}const u=t(a,[["render",n]]);export{g as __pageData,u as default};
